package ua.university.sms.model.entity;
import jakarta.persistence.*;import jakarta.validation.constraints.*;import java.time.*;
@Entity @Table(uniqueConstraints=@UniqueConstraint(columnNames={"student_id","course_id"})) public class Enrollment{@Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id;@ManyToOne(optional=false) private Student student;@ManyToOne(optional=false) private Course course;private boolean paid=false;@DecimalMin("0.0")@DecimalMax("100.0") private Double grade;private Instant enrolledAt=Instant.now(); public Long getId(){return id;}public void setId(Long id){this.id=id;}public Student getStudent(){return student;}public void setStudent(Student student){this.student=student;}public Course getCourse(){return course;}public void setCourse(Course course){this.course=course;}public boolean isPaid(){return paid;}public void setPaid(boolean paid){this.paid=paid;}public Double getGrade(){return grade;}public void setGrade(Double grade){this.grade=grade;}public Instant getEnrolledAt(){return enrolledAt;}public void setEnrolledAt(Instant enrolledAt){this.enrolledAt=enrolledAt;}}
